// Read the order (webhook body) and build the two messages.
const o = $input.first().json.body ?? $input.first().json;

// Normalise the Indian mobile to WhatsApp format: 91 + 10 digits.
const digits = String(o.phone || '').replace(/\D/g, '').replace(/^0+/, '');
const customerPhone = digits.length === 10 ? '91' + digits : digits;

// >>> SET THE OWNER'S / STAFF WHATSAPP NUMBER HERE (country code + number, no +) <<<
const ownerPhone = '91XXXXXXXXXX';

const rupees = (n) => 'Rs.' + Number(n || 0).toFixed(2);
const order = o.orderId ? '#' + o.orderId : '';
const items = o.itemsSummary || 'your order';
const addr  = o.address || 'address on file';

const customerMessage =
  `Hi ${o.name}, thanks for ordering with SliceMatic! 🍕\n\n` +
  `Your order ${order} is confirmed ✅\n` +
  `--------------------------------\n` +
  `${items}\n` +
  `--------------------------------\n` +
  `Amount: ${rupees(o.total)} (${o.payment_mode})\n` +
  `🛵 Delivering to: ${addr}\n\n` +
  `Arriving hot in ~30 minutes. See you soon!`;

const ownerMessage =
  `🔔 NEW ORDER ${order}\n` +
  `--------------------------------\n` +
  `${items}\n` +
  `Total pizzas: ${o.quantity}\n` +
  `--------------------------------\n` +
  `Subtotal: ${rupees(o.subtotal)}\n` +
  `Discount: ${rupees(o.discount)}\n` +
  `GST: ${rupees(o.gst)}\n` +
  `TOTAL: ${rupees(o.total)} (${o.payment_mode})\n\n` +
  `📍 Deliver to: ${addr}` + (o.geo ? ` (pin: ${o.geo})` : '') + `\n` +
  `👤 ${o.name} · +${customerPhone}\n` +
  `⏱️ Start prep now — 30-min SLA.`;

return [{ json: { customerPhone, ownerPhone, customerMessage, ownerMessage } }];
